285 
286   // Add the loop mapping to the LoopInfo object...
287   LIB.BBMap[NewBB] = L;
288 
289   // Add the basic block to this loop and all parent loops...
290   while (L) {
291     L->addBlockEntry(NewBB);
292     L = L->getParentLoop();
293   }
